export function getBass4ChordBySlug(slug) {
  return BASS4_CHORDS.find(c => c.name.toLowerCase() === slug.toLowerCase())
}

export function getBass5ChordBySlug(slug) {
  return BASS5_CHORDS.find(c => c.name.toLowerCase() === slug.toLowerCase())
}

export function getBass4ChordsForRoot(root) {
  return BASS4_CHORDS.filter(c => c.root === root)
}

export function getBass5ChordsForRoot(root) {
  return BASS5_CHORDS.filter(c => c.root === root)
}
